() => {
  // Walk fiber tree to find a node whose memoizedState contains the Zustand store
  const root = document.getElementById('root');
  const fiberKey = Object.keys(root).find(k => k.startsWith('__reactFiber') || k.startsWith('__reactContainer'));
  const rootFiber = root[fiberKey];

  function walkFiber(fiber, depth = 0) {
    if (!fiber || depth > 50) return null;
    // Check memoizedState chain for Zustand store shape (has getState, setState, subscribe)
    let ms = fiber.memoizedState;
    while (ms) {
      const q = ms.queue;
      // Zustand hook stores a memoizedState that's a primitive (the selected state slice)
      // The store itself is in the closure — look for it in pendingProps or stateNode
      if (ms.memoizedState && typeof ms.memoizedState === 'object' && 
          typeof ms.memoizedState.getState === 'function' &&
          typeof ms.memoizedState.setState === 'function') {
        return ms.memoizedState;
      }
      ms = ms.next;
    }
    // Check stateNode
    if (fiber.stateNode && typeof fiber.stateNode.getState === 'function') {
      return fiber.stateNode;
    }
    // Recurse child then sibling
    const fromChild = walkFiber(fiber.child, depth + 1);
    if (fromChild) return fromChild;
    return walkFiber(fiber.sibling, depth + 1);
  }

  const store = walkFiber(rootFiber);
  if (!store) return 'store not found via fiber walk';
  return { found: true, state: store.getState() };
}

