  const axios = window.__appAxios;

  // Remove existing response interceptors to prevent 401 → logout
  // axios.interceptors.response.handlers is an array of {fulfilled, rejected} objects
  const handlers = axios.interceptors.response.handlers;
  // Clear all handlers
  if (handlers) {
    for (let i = 0; i < handlers.length; i++) {
      axios.interceptors.response.eject(i);
    }
  }
  // Re-add a pass-through interceptor that does NOT call logout
  axios.interceptors.response.use(
    (response) => response,
    (error) => Promise.reject(error)
  );

  return { interceptorCount: axios.interceptors.response.handlers?.length };
}

